import {
  BrowserRouter,
  Routes,
  Route,
  Link
} from "react-router-dom";

import Login from "./pages/Login";
import Signup from "./pages/Signup";
import Dashboard from "./pages/Dashboard";
import AddEmployee from "./pages/AddEmployee";

import ProtectedRoute from "./components/ProtectedRoute";

function App() {

  const token = localStorage.getItem("token");

  return (

    <BrowserRouter>

      <div
        style={{
          padding: "20px",
          display: "flex",
          gap: "20px"
        }}
      >

        {!token && (

          <>
            <Link to="/">
              Login
            </Link>

            <Link to="/signup">
              Signup
            </Link>
          </>

        )}

        {token && (

          <>
            <Link to="/dashboard">
              Dashboard
            </Link>

            <Link to="/add-employee">
              Add Employee
            </Link>
          </>

        )}

      </div>

      <Routes>

        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/signup"
          element={<Signup />}
        />

        <Route
          path="/dashboard"
          element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/add-employee"
          element={
            <ProtectedRoute>
              <AddEmployee />
            </ProtectedRoute>
          }
        />

      </Routes>

    </BrowserRouter>

  );

}

export default App;
